mapper.select:
SELECT 
FROM posts p JOIN users u ON u.id = p.user_id
WHERE (p.deleted_at IS NULL OR EXISTS (SELECT 1 FROM comments c2 WHERE c2.post_id = p.id))
AND p.id < #{cursor}
AND p.id > #{sinceId}
ORDER BY

    p.id ASC
    p.id DESC

LIMIT #{limit}

SELECT FROM posts p JOIN users u ON u.id = p.user_id JOIN follows fl ON fl.follower_id = #{currentUserId} AND fl.followee_id = p.user_id WHERE (p.deleted_at IS NULL OR EXISTS (SELECT 1 FROM comments c2 WHERE c2.post_id = p.id)) AND p.id < #{cursor} AND p.id > #{sinceId} ORDER BY
p.id ASC p.id DESC
LIMIT #{limit}

SELECT id, user_id, body, created_at, updated_at, deleted_at
FROM posts
WHERE id = #{postId}
